 15→/**
 16→ * Quiz submission API route.
 17→ * POST /api/training/{tenant}/module/{moduleIndex}/quiz
 18→ * Accepts all quiz answers, scores them, and finalises the training module.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { resolveModel } from "@/intake/ai-model-resolver";
 23→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 24→import { logModuleCompleted, logQuizSubmitted } from "@/training/audit";
 25→import { EvaluationError, evaluateFreeText } from "@/training/evaluator";
 26→import { QuizSubmissionSchema } from "@/training/schemas";
 27→import { computeModuleScore, scoreMcAnswer } from "@/training/score-calculator";
 28→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 29→import { transitionModule, transitionSession } from "@/training/state-machine";
 30→import { NextResponse } from "next/server";
 31→
 32→export async function POST(
 33→  request: Request,
 34→  { params }: { params: Promise<{ tenant: string; moduleIndex: string }> },
 35→) {
 36→  const { tenant, moduleIndex: moduleIndexStr } = await params;
 37→  const tenantId = request.headers.get("x-tenant-id");
 38→  const employeeId = request.headers.get("x-employee-id");
 39→
 40→  // 1. Auth check
 41→  if (!tenantId || !employeeId || tenantId !== tenant) {
 42→    return NextResponse.json(
 43→      { error: "unauthorized", message: "Not authenticated" },
 44→      { status: 401 },
 45→    );
 46→  }
 47→
 48→  // 2. Parse and validate moduleIndex (0-7)
 49→  const moduleIndex = Number.parseInt(moduleIndexStr, 10);
 50→  if (Number.isNaN(moduleIndex) || moduleIndex < 0 || moduleIndex > 7) {
 51→    return NextResponse.json(
 52→      { error: "validation_error", message: "moduleIndex must be an integer between 0 and 7" },
 53→      { status: 400 },
 54→    );
 55→  }
 56→
 57→  // 3. Parse request body
 58→  let body: unknown;
 59→  try {
 60→    body = await request.json();
 61→  } catch {
 62→    return NextResponse.json(
 63→      { error: "invalid_request", message: "Invalid JSON body" },
 64→      { status: 400 },
 65→    );
 66→  }
 67→
 68→  const parsed = QuizSubmissionSchema.safeParse(body);
 69→  if (!parsed.success) {
 70→    return NextResponse.json(
 71→      { error: "validation_error", message: "Invalid quiz submission data" },
 72→      { status: 400 },
 73→    );
 74→  }
 75→
 76→  const submission = parsed.data;
 77→
 78→  // Initialise repositories
 79→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 80→  const sessionRepo = new SessionRepository(storage);
 81→
 82→  await storage.initialize();
 83→
 84→  // 4. Find active session
 85→  const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 86→  if (!session) {
 87→    return NextResponse.json(
 88→      { error: "not_found", message: "No active training session found" },
 89→      { status: 404 },
 90→    );
 91→  }
 92→
 93→  // Find the module
 94→  const mod = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
 95→  if (!mod) {
 96→    return NextResponse.json({ error: "not_found", message: "Module not found" }, { status: 404 });
 97→  }
 98→
 99→  // 5. Guard: module must be in `quiz-active` state
100→  if (mod.status !== "quiz-active") {
101→    return NextResponse.json(
102→      {
103→        error: "conflict",
104→        message: `Module is in '${mod.status}' state; expected 'quiz-active'`,
105→      },
106→      { status: 409 },
107→    );
108→  }
109→
110→  if (!mod.content) {
111→    return NextResponse.json(
112→      { error: "not_found", message: "Module content not available" },
113→      { status: 404 },
114→    );
115→  }
116→
117→  // 6. Validate all quiz questions are answered
118→  const expectedCount = mod.content.quiz.questions.length;
119→  if (submission.answers.length !== expectedCount) {
120→    return NextResponse.json(
121→      {
122→        error: "validation_error",
123→        message: `Expected ${expectedCount} answers but received ${submission.answers.length}`,
124→      },
125→      { status: 400 },
126→    );
127→  }
128→
129→  // Resolve AI model upfront if any free-text answers exist
130→  const hasFreeText = submission.answers.some((a) => a.responseType === "free-text");
131→  let model: ReturnType<typeof resolveModel> | undefined;
132→
133→  if (hasFreeText) {
134→    const snapshot = getSnapshot();
135→    const tenantConfig = snapshot?.tenants.get(tenantId);
136→    if (!tenantConfig) {
137→      return NextResponse.json(
138→        { error: "not_found", message: "Tenant configuration not found" },
139→        { status: 404 },
140→      );
141→    }
142→    model = resolveModel(tenantConfig);
143→  }
144→
145→  // 7. Score each answer
146→  const now = new Date().toISOString();
147→  const quizAnswers: Array<{
148→    questionId: string;
149→    responseType: "multiple-choice" | "free-text";
150→    selectedOption?: string;
151→    freeTextResponse?: string;
152→    score: number;
153→    llmRationale?: string;
154→    submittedAt: string;
155→  }> = [];
156→
157→  try {
158→    for (const answer of submission.answers) {
159→      const question = mod.content.quiz.questions.find((q) => q.id === answer.questionId);
160→      if (!question) {
161→        return NextResponse.json(
162→          { error: "validation_error", message: `Unknown question id '${answer.questionId}'` },
163→          { status: 400 },
164→        );
165→      }
166→
167→      let score: number;
168→      let llmRationale: string | undefined;
169→
170→      if (answer.responseType === "multiple-choice") {
171→        const correctOption = question.options?.find((o) => o.correct)?.key;
172→        if (!correctOption) {
173→          return NextResponse.json(
174→            {
175→              error: "internal_error",
176→              message: `Question '${answer.questionId}' has no correct option defined`,
177→            },
178→            { status: 500 },
179→          );
180→        }
181→        score = scoreMcAnswer(answer.selectedOption ?? "", correctOption);
182→      } else {
183→        // free-text — model is guaranteed to be set when hasFreeText is true
184→        const evaluation = await evaluateFreeText(
185→          question.text,
186→          question.rubric ?? "",
187→          answer.freeTextResponse ?? "",
188→          // biome-ignore lint/style/noNonNullAssertion: model is set whenever hasFreeText is true
189→          model!,
190→        );
191→        score = evaluation.score;
192→        llmRationale = evaluation.rationale;
193→      }
194→
195→      quizAnswers.push({
196→        questionId: answer.questionId,
197→        responseType: answer.responseType,
198→        ...(answer.selectedOption !== undefined ? { selectedOption: answer.selectedOption } : {}),
199→        ...(answer.freeTextResponse !== undefined
200→          ? { freeTextResponse: answer.freeTextResponse }
201→          : {}),
202→        score,
203→        ...(llmRationale !== undefined ? { llmRationale } : {}),
204→        submittedAt: now,
205→      });
206→    }
207→  } catch (error) {
208→    if (error instanceof EvaluationError) {
209→      return NextResponse.json(
210→        { error: "ai_unavailable", message: "AI evaluation service temporarily unavailable" },
211→        { status: 503 },
212→      );
213→    }
214→    return NextResponse.json(
215→      { error: "internal_error", message: "An unexpected error occurred during scoring" },
216→      { status: 500 },
217→    );
218→  }
219→
220→  // 9. Compute module score
221→  const scenarioScores = mod.scenarioResponses.map((r) => r.score);
222→  const quizScores = quizAnswers.map((a) => a.score);
223→  const moduleScore = computeModuleScore(scenarioScores, quizScores) ?? 0;
224→
225→  // 10. Transition module to `scored`
226→  const nextModuleStatus = transitionModule(mod.status, "quiz-scored");
227→
228→  // 11. Update module with quizAnswers and moduleScore
229→  try {
230→    await sessionRepo.updateModule(
231→      tenantId,
232→      mod.id,
233→      {
234→        status: nextModuleStatus,
235→        quizAnswers,
236→        moduleScore,
237→      },
238→      mod.version,
239→    );
240→  } catch (updateError) {
241→    if (updateError instanceof VersionConflictError) {
242→      return NextResponse.json(
243→        { error: "conflict", message: "Resource was modified by another request" },
244→        { status: 409 },
245→      );
246→    }
247→    throw updateError;
248→  }
249→
250→  // 12. Log audit events
251→  await logModuleCompleted(
252→    storage,
253→    tenantId,
254→    employeeId,
255→    session.id,
256→    moduleIndex,
257→    mod.title,
258→    moduleScore,
259→  );
260→
261→  const mcCount = quizAnswers.filter((a) => a.responseType === "multiple-choice").length;
262→  const freeTextCount = quizAnswers.filter((a) => a.responseType === "free-text").length;
263→  await logQuizSubmitted(
264→    storage,
265→    tenantId,
266→    employeeId,
267→    session.id,
268→    moduleIndex,
269→    quizAnswers.length,
270→    mcCount,
271→    freeTextCount,
272→  );
273→
274→  // 13. Check if this is the last module; if so, transition session to `evaluating`
275→  const allModules = await sessionRepo.findModulesBySession(tenantId, session.id);
276→  // Count modules that are now scored (the one we just updated plus previously scored ones)
277→  const scoredCount = allModules.filter((m) => m.status === "scored").length;
278→  const totalModules = allModules.length;
279→
280→  if (scoredCount === totalModules) {
281→    const freshSession = await sessionRepo.findActiveSession(tenantId, employeeId);
282→    if (!freshSession || freshSession.id !== session.id) {
283→      return NextResponse.json(
284→        { error: "conflict", message: "Resource was modified by another request" },
285→        { status: 409 },
286→      );
287→    }
288→    const nextSessionStatus = transitionSession(freshSession.status, "all-modules-scored");
289→    try {
290→      await sessionRepo.updateSession(
291→        tenantId,
292→        freshSession.id,
293→        { status: nextSessionStatus },
294→        freshSession.version,
295→      );
296→    } catch (sessionUpdateError) {
297→      if (sessionUpdateError instanceof VersionConflictError) {
298→        return NextResponse.json(
299→          { error: "conflict", message: "Resource was modified by another request" },
300→          { status: 409 },
301→        );
302→      }
303→      throw sessionUpdateError;
304→    }
305→  }
306→
307→  // 14. Return 200
308→  return NextResponse.json({
309→    moduleIndex,
310→    moduleScore,
311→    answers: quizAnswers.map((a) => ({
312→      questionId: a.questionId,
313→      score: a.score,
314→      ...(a.llmRationale !== undefined ? { rationale: a.llmRationale } : {}),
315→    })),
316→  });
317→}
318→

