 15→/**
 16→ * Scenario submission API route.
 17→ * POST /api/training/{tenant}/module/{moduleIndex}/scenario
 18→ * Accepts a scenario response, scores it, and updates the training module.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { resolveModel } from "@/intake/ai-model-resolver";
 23→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 24→import { EvaluationError, evaluateFreeText } from "@/training/evaluator";
 25→import { ScenarioSubmissionSchema } from "@/training/schemas";
 26→import type { ModuleStatus } from "@/training/schemas";
 27→import { scoreMcAnswer } from "@/training/score-calculator";
 28→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 29→import { transitionModule } from "@/training/state-machine";
 30→import { NextResponse } from "next/server";
 31→
 32→export async function POST(
 33→  request: Request,
 34→  { params }: { params: Promise<{ tenant: string; moduleIndex: string }> },
 35→) {
 36→  const { tenant, moduleIndex: moduleIndexStr } = await params;
 37→  const tenantId = request.headers.get("x-tenant-id");
 38→  const employeeId = request.headers.get("x-employee-id");
 39→
 40→  // 1. Auth check
 41→  if (!tenantId || !employeeId || tenantId !== tenant) {
 42→    return NextResponse.json(
 43→      { error: "unauthorized", message: "Not authenticated" },
 44→      { status: 401 },
 45→    );
 46→  }
 47→
 48→  // 2. Parse and validate moduleIndex (0-19)
 49→  const moduleIndex = Number.parseInt(moduleIndexStr, 10);
 50→  if (Number.isNaN(moduleIndex) || moduleIndex < 0 || moduleIndex > 19) {
 51→    return NextResponse.json(
 52→      { error: "validation_error", message: "moduleIndex must be an integer between 0 and 19" },
 53→      { status: 400 },
 54→    );
 55→  }
 56→
 57→  // 3. Parse request body
 58→  let body: unknown;
 59→  try {
 60→    body = await request.json();
 61→  } catch {
 62→    return NextResponse.json(
 63→      { error: "invalid_request", message: "Invalid JSON body" },
 64→      { status: 400 },
 65→    );
 66→  }
 67→
 68→  const parsed = ScenarioSubmissionSchema.safeParse(body);
 69→  if (!parsed.success) {
 70→    return NextResponse.json(
 71→      { error: "validation_error", message: "Invalid scenario submission data" },
 72→      { status: 400 },
 73→    );
 74→  }
 75→
 76→  const submission = parsed.data;
 77→
 78→  // Initialise repositories
 79→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 80→  const sessionRepo = new SessionRepository(storage);
 81→
 82→  await storage.initialize();
 83→
 84→  // 4. Find active session
 85→  const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 86→  if (!session) {
 87→    return NextResponse.json(
 88→      { error: "not_found", message: "No active training session found" },
 89→      { status: 404 },
 90→    );
 91→  }
 92→
 93→  // Find the module
 94→  const mod = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
 95→  if (!mod) {
 96→    return NextResponse.json({ error: "not_found", message: "Module not found" }, { status: 404 });
 97→  }
 98→
 99→  // 5. Guard: module must be in `learning` or `scenario-active` state
100→  if (mod.status !== "learning" && mod.status !== "scenario-active") {
101→    return NextResponse.json(
102→      {
103→        error: "conflict",
104→        message: `Module is in '${mod.status}' state; expected 'learning' or 'scenario-active'`,
105→      },
106→      { status: 409 },
107→    );
108→  }
109→
110→  // 6. Find the scenario in module.content.scenarios by scenarioId
111→  if (!mod.content) {
112→    return NextResponse.json(
113→      { error: "not_found", message: "Module content not available" },
114→      { status: 404 },
115→    );
116→  }
117→
118→  const scenario = mod.content.scenarios.find((s) => s.id === submission.scenarioId);
119→  if (!scenario) {
120→    return NextResponse.json(
121→      { error: "not_found", message: `Scenario '${submission.scenarioId}' not found in module` },
122→      { status: 404 },
123→    );
124→  }
125→
126→  // 7. Guard: scenario must not already be answered
127→  const alreadyAnswered = mod.scenarioResponses.some((r) => r.scenarioId === submission.scenarioId);
128→  if (alreadyAnswered) {
129→    return NextResponse.json(
130→      {
131→        error: "conflict",
132→        message: `Scenario '${submission.scenarioId}' has already been answered`,
133→      },
134→      { status: 409 },
135→    );
136→  }
137→
138→  // 8. Score the response
139→  let score: number;
140→  let llmRationale: string | undefined;
141→
142→  try {
143→    if (submission.responseType === "multiple-choice") {
144→      const correctOption = scenario.options?.find((o) => o.correct)?.key;
145→      if (!correctOption) {
146→        return NextResponse.json(
147→          { error: "internal_error", message: "Scenario has no correct option defined" },
148→          { status: 500 },
149→        );
150→      }
151→      score = scoreMcAnswer(submission.selectedOption ?? "", correctOption);
152→    } else {
153→      // free-text
154→      const snapshot = getSnapshot();
155→      const tenantConfig = snapshot?.tenants.get(tenantId);
156→      if (!tenantConfig) {
157→        return NextResponse.json(
158→          { error: "not_found", message: "Tenant configuration not found" },
159→          { status: 404 },
160→        );
161→      }
162→      const model = resolveModel(tenantConfig);
163→      const evaluation = await evaluateFreeText(
164→        scenario.narrative,
165→        scenario.rubric ?? "",
166→        submission.freeTextResponse ?? "",
167→        model,
168→      );
169→      score = evaluation.score;
170→      llmRationale = evaluation.rationale;
171→    }
172→  } catch (error) {
173→    if (error instanceof EvaluationError) {
174→      return NextResponse.json(
175→        { error: "ai_unavailable", message: "AI evaluation service temporarily unavailable" },
176→        { status: 503 },
177→      );
178→    }
179→    return NextResponse.json(
180→      { error: "internal_error", message: "An unexpected error occurred during scoring" },
181→      { status: 500 },
182→    );
183→  }
184→
185→  // 9. Build ScenarioResponse record
186→  const now = new Date().toISOString();
187→  const scenarioResponse = {
188→    scenarioId: submission.scenarioId,
189→    responseType: submission.responseType,
190→    ...(submission.selectedOption !== undefined
191→      ? { selectedOption: submission.selectedOption }
192→      : {}),
193→    ...(submission.freeTextResponse !== undefined
194→      ? { freeTextResponse: submission.freeTextResponse }
195→      : {}),
196→    score,
197→    ...(llmRationale !== undefined ? { llmRationale } : {}),
198→    submittedAt: now,
199→  };
200→
201→  // 10. Determine next status (transition to scenario-active if currently in learning)
202→  let nextStatus: ModuleStatus = mod.status;
203→  if (mod.status === "learning") {
204→    nextStatus = transitionModule(mod.status, "start-scenario");
205→  }
206→
207→  // 11. Append response
208→  const updatedResponses = [...mod.scenarioResponses, scenarioResponse];
209→
210→  // 12. Determine if all scenarios answered → transition to quiz-active
211→  const allScenariosAnswered = updatedResponses.length >= mod.content.scenarios.length;
212→  if (allScenariosAnswered) {
213→    nextStatus = transitionModule("scenario-active", "scenarios-complete");
214→  }
215→
216→  // 13. Update module via sessionRepo.updateModule
217→  try {
218→    await sessionRepo.updateModule(
219→      tenantId,
220→      mod.id,
221→      {
222→        status: nextStatus,
223→        scenarioResponses: updatedResponses,
224→      },
225→      mod.version,
226→    );
227→  } catch (updateError) {
228→    if (updateError instanceof VersionConflictError) {
229→      return NextResponse.json(
230→        { error: "conflict", message: "Resource was modified by another request" },
231→        { status: 409 },
232→      );
233→    }
234→    throw updateError;
235→  }
236→
237→  // 14. Return 200 with result
238→  return NextResponse.json({
239→    scenarioId: submission.scenarioId,
240→    score,
241→    ...(llmRationale !== undefined ? { rationale: llmRationale } : {}),
242→  });
243→}
