 15→/**
 16→ * POST /api/training/{tenant}/module/{moduleIndex}/content
 17→ * Generates content for a specific training module.
 18→ * Idempotent: returns existing content if already generated.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { resolveModel } from "@/intake/ai-model-resolver";
 23→import { ProfileRepository } from "@/intake/profile-repository";
 24→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 25→import { ModuleGenerationError, generateModuleContent } from "@/training/module-generator";
 26→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 27→import { StateTransitionError, transitionModule } from "@/training/state-machine";
 28→import type { ModuleContent } from "@/training/types";
 29→import { NextResponse } from "next/server";
 30→
 31→// ---------------------------------------------------------------------------
 32→// Helper — strip server-only fields from module content for client
 33→// ---------------------------------------------------------------------------
 34→
 35→function toClientContent(content: ModuleContent) {
 36→  return {
 37→    ...content,
 38→    scenarios: content.scenarios.map(({ rubric: _rubric, ...s }) => ({
 39→      ...s,
 40→      options: s.options?.map(({ correct: _correct, ...o }) => o),
 41→    })),
 42→    quiz: {
 43→      questions: content.quiz.questions.map(({ rubric: _rubric, ...q }) => ({
 44→        ...q,
 45→        options: q.options?.map(({ correct: _correct, ...o }) => o),
 46→      })),
 47→    },
 48→  };
 49→}
 50→
 51→// ---------------------------------------------------------------------------
 52→// POST handler
 53→// ---------------------------------------------------------------------------
 54→
 55→export async function POST(
 56→  request: Request,
 57→  { params }: { params: Promise<{ tenant: string; moduleIndex: string }> },
 58→) {
 59→  const { tenant: tenantSlug, moduleIndex: moduleIndexStr } = await params;
 60→  const tenantId = request.headers.get("x-tenant-id");
 61→  const employeeId = request.headers.get("x-employee-id");
 62→
 63→  // 1. Auth check
 64→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 65→    return NextResponse.json(
 66→      { error: "unauthorized", message: "Not authenticated" },
 67→      { status: 401 },
 68→    );
 69→  }
 70→
 71→  // 2. Parse and validate moduleIndex
 72→  const moduleIndex = Number(moduleIndexStr);
 73→  if (Number.isNaN(moduleIndex) || moduleIndex < 0 || moduleIndex > 7) {
 74→    return NextResponse.json(
 75→      { error: "invalid_request", message: "Invalid module index" },
 76→      { status: 400 },
 77→    );
 78→  }
 79→
 80→  // Initialise repositories
 81→  const adapter = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 82→  const sessionRepo = new SessionRepository(adapter);
 83→  const profileRepo = new ProfileRepository(adapter);
 84→
 85→  await adapter.initialize();
 86→
 87→  let activeSessionId: string | undefined;
 88→
 89→  try {
 90→    // 3. Find active session
 91→    const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 92→    if (session) activeSessionId = session.id;
 93→    if (!session) {
 94→      return NextResponse.json(
 95→        { error: "not_found", message: "No active training session found" },
 96→        { status: 404 },
 97→      );
 98→    }
 99→
100→    // 4. Find the module
101→    const module = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
102→    if (!module) {
103→      return NextResponse.json(
104→        { error: "not_found", message: "Module not found" },
105→        { status: 404 },
106→      );
107→    }
108→
109→    // 5. Idempotent: return existing content if already generated
110→    if (module.content !== null) {
111→      return NextResponse.json(toClientContent(module.content), { status: 200 });
112→    }
113→
114→    // 6. Guard: module must be in `locked` status
115→    if (module.status !== "locked") {
116→      return NextResponse.json(
117→        {
118→          error: "conflict",
119→          message: `Module is in '${module.status}' state, expected 'locked'`,
120→        },
121→        { status: 409 },
122→      );
123→    }
124→
125→    // Guard: previous module must be `scored` (for index > 0)
126→    if (moduleIndex > 0) {
127→      const previousModule = await sessionRepo.findModule(tenantId, session.id, moduleIndex - 1);
128→      if (!previousModule || previousModule.status !== "scored") {
129→        return NextResponse.json(
130→          {
131→            error: "conflict",
132→            message: "Previous module must be scored before generating content",
133→          },
134→          { status: 409 },
135→        );
136→      }
137→    }
138→
139→    // 7. Transition module to `content-generating`
140→    const generatingStatus = transitionModule(module.status, "generate-content");
141→    await sessionRepo.updateModule(
142→      tenantId,
143→      module.id,
144→      { status: generatingStatus },
145→      module.version,
146→    );
147→
148→    // 8. Find confirmed role profile
149→    const roleProfile = await profileRepo.findByEmployee(tenantId, employeeId);
150→    if (!roleProfile) {
151→      return NextResponse.json(
152→        { error: "not_found", message: "Role profile not found" },
153→        { status: 404 },
154→      );
155→    }
156→
157→    // 9. Resolve AI model from tenant config
158→    const snapshot = getSnapshot();
159→    const tenant = snapshot?.tenants.get(tenantSlug);
160→    if (!tenant) {
161→      return NextResponse.json(
162→        { error: "not_found", message: "Tenant not found" },
163→        { status: 404 },
164→      );
165→    }
166→    const model = resolveModel(tenant);
167→
168→    // 10. Generate module content
169→    const moduleOutline = {
170→      title: module.title,
171→      topicArea: module.topicArea,
172→      jobExpectationIndices: module.jobExpectationIndices,
173→    };
174→    const content = await generateModuleContent(moduleOutline, roleProfile, model);
175→
176→    // 11. Update module: set content, transition to `learning`
177→    const learningStatus = transitionModule(generatingStatus, "content-ready");
178→    // Re-fetch module to get updated version after first update
179→    const updatedModule = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
180→    if (!updatedModule) {
181→      return NextResponse.json(
182→        { error: "not_found", message: "Module not found after update" },
183→        { status: 404 },
184→      );
185→    }
186→    await sessionRepo.updateModule(
187→      tenantId,
188→      module.id,
189→      { content, status: learningStatus },
190→      updatedModule.version,
191→    );
192→
193→    // 12. Return 200 with client-safe content
194→    return NextResponse.json(toClientContent(content), { status: 200 });
195→  } catch (error) {
196→    if (error instanceof ModuleGenerationError) {
197→      // Roll back module status to `locked` so future retries are not blocked.
198→      try {
199→        const stuckModule = activeSessionId
200→          ? await sessionRepo.findModule(tenantId, activeSessionId, moduleIndex)
201→          : null;
202→        if (stuckModule && stuckModule.status === "content-generating") {
203→          await sessionRepo.updateModule(
204→            tenantId,
205→            stuckModule.id,
206→            { status: "locked" },
207→            stuckModule.version,
208→          );
209→        }
210→      } catch {
211→        // Best-effort rollback — ignore secondary errors
212→      }
213→      if (error.code === "ai_unavailable") {
214→        return NextResponse.json(
215→          { error: "ai_unavailable", message: "AI service temporarily unavailable" },
216→          { status: 503 },
217→        );
218→      }
219→      return NextResponse.json(
220→        { error: "generation_failed", message: error.message },
221→        { status: 422 },
222→      );
223→    }
224→    if (error instanceof VersionConflictError) {
225→      return NextResponse.json(
226→        { error: "conflict", message: "Resource was modified by another request" },
227→        { status: 409 },
228→      );
229→    }
230→    if (error instanceof StateTransitionError) {
231→      return NextResponse.json({ error: "conflict", message: error.message }, { status: 409 });
232→    }
233→    return NextResponse.json(
234→      { error: "internal_error", message: "An unexpected error occurred" },
235→      { status: 500 },
236→    );
237→  }
238→}
