import {
  CurriculumOutlineModuleSchema,
  CurriculumOutlineSchema,
  FreeTextEvaluationSchema,
  McOptionClientSchema,
  McOptionSchema,
  ModuleContentClientSchema,
  ModuleContentSchema,
  ModuleStatusSchema,
  QuizAnswerSchema,
  QuizQuestionClientSchema,
  QuizQuestionSchema,
  QuizSubmissionSchema,
  ResponseTypeSchema,
  ScenarioClientSchema,
